-- Initial agentlink scaffold migration.
-- Generated by cli/scripts/regen-baseline-migration.ts via pg-delta plan.
-- DO NOT HAND-EDIT — regenerate by running:
--   npx tsx cli/scripts/regen-baseline-migration.ts --from <scaffold-project-dir>
-- after changing anything under cli/src/template/supabase/schemas/.

-- Defer function-body validation for this migration. pg-delta orders
-- functions ahead of the tables their bodies reference (SQL function
-- bodies aren't tracked as catalog dependencies), so body-checking
-- must be off or e.g. _auth_has_role (references public.roles) fails
-- with "relation public.roles does not exist". Scoped to this
-- migration's transaction.
SET check_function_bodies = false;
CREATE FUNCTION api._admin_enqueue_task (
  function_name text,
  payload       jsonb   DEFAULT '{}'::jsonb,
  delay_seconds integer DEFAULT 0
)
  RETURNS bigint
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  msg_id bigint;
BEGIN
  SELECT pgmq.send(
    'agentlink_tasks',
    jsonb_build_object(
      'function_name', function_name,
      'payload', payload
    ),
    delay_seconds
  ) INTO msg_id;

  -- Fire the queue worker via pg_net (fire-and-forget)
  PERFORM public._internal_admin_call_edge_function('internal-queue-worker');

  RETURN msg_id;
END;
$function$;

REVOKE ALL ON FUNCTION api._admin_enqueue_task(text, jsonb, integer) FROM authenticated;

CREATE FUNCTION api._admin_queue_archive (
  id bigint
)
  RETURNS boolean
  LANGUAGE sql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
  SELECT pgmq.archive('agentlink_tasks', id);
$function$;

REVOKE ALL ON FUNCTION api._admin_queue_archive(bigint) FROM authenticated;

CREATE FUNCTION api._admin_queue_delete (
  id bigint
)
  RETURNS boolean
  LANGUAGE sql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
  SELECT pgmq.delete('agentlink_tasks', id);
$function$;

REVOKE ALL ON FUNCTION api._admin_queue_delete(bigint) FROM authenticated;

CREATE FUNCTION api._admin_queue_read (
  qty integer DEFAULT 5,
  vt  integer DEFAULT 30
)
  RETURNS TABLE (
    msg_id      bigint,
    read_ct     integer,
    enqueued_at timestamp with time zone,
    vt          timestamp with time zone,
    message     jsonb
  )
  LANGUAGE sql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
  SELECT msg_id, read_ct, enqueued_at, vt, message FROM pgmq.read('agentlink_tasks', vt, qty);
$function$;

REVOKE ALL ON FUNCTION api._admin_queue_read(integer, integer) FROM authenticated;

CREATE FUNCTION api.invitation_accept (
  p_token uuid
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id uuid := (SELECT auth.uid());
  v_result  jsonb;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  v_result := public._internal_admin_complete_invitation(v_user_id, p_token);

  -- Pin to this session — the user almost always wants to start working in the
  -- tenant they just accepted into. They can switch later with tenant_select.
  -- Skip when there's no session_id (service-role / admin-API context); the
  -- hook's "oldest membership" fallback resolves the tenant on next mint.
  IF NULLIF(auth.jwt()->>'session_id', '') IS NOT NULL THEN
    PERFORM public._internal_admin_set_session_tenant(
      v_user_id,
      (v_result->>'id')::uuid,
      v_result->>'role'
    );
  END IF;

  RETURN v_result;
END;
$function$;

CREATE FUNCTION api.invitation_create (
  p_email text,
  p_role  text DEFAULT 'member'::text
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id uuid := (SELECT auth.uid());
  v_tenant_id uuid := public._auth_tenant_id();
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF v_tenant_id IS NULL THEN
    RAISE EXCEPTION 'No tenant selected';
  END IF;

  -- Primary permission gate (403 if denied). The DEFINER helper below ALSO
  -- re-checks role_permissions from the memberships row — kept deliberately:
  -- it's DB-authoritative (defends stale JWTs + direct helper calls), where
  -- this guard is the fast JWT-only, user-facing check.
  PERFORM public.auth_verify_access('invitation.create');

  RETURN public._internal_admin_create_invitation(v_user_id, v_tenant_id, p_email, p_role);
END;
$function$;

CREATE FUNCTION api.invitation_list()
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_tenant_id uuid := public._auth_tenant_id();
  v_result jsonb;
BEGIN
  IF v_tenant_id IS NULL THEN
    RAISE EXCEPTION 'No tenant selected';
  END IF;

  -- Primary permission gate (same permission that gates creating invitations).
  PERFORM public.auth_verify_access('invitation.create');

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'id', i.id,
    'email', i.email,
    'role', i.role,
    'invited_by', i.invited_by,
    'expires_at', i.expires_at,
    'created_at', i.created_at
  ) ORDER BY i.created_at DESC), '[]'::jsonb)
  INTO v_result
  FROM public.invitations i
  WHERE i.tenant_id = v_tenant_id
    AND i.accepted_at IS NULL
    AND i.expires_at > now();

  RETURN v_result;
END;
$function$;

CREATE FUNCTION api.invitation_preview (
  p_token uuid
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  v_inv record;
  v_inviter_name text;
BEGIN
  SELECT
    i.email,
    i.role,
    i.invited_by,
    i.accepted_at,
    i.expires_at,
    i.tenant_id,
    t.name AS tenant_name,
    t.slug AS tenant_slug
  INTO v_inv
  FROM public.invitations i
  JOIN public.tenants t ON t.id = i.tenant_id
  WHERE i.token = p_token;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'not_found');
  END IF;

  IF v_inv.accepted_at IS NOT NULL THEN
    -- Surface tenant_name/slug so the "already accepted" screen can
    -- offer a "Continue to <workspace>" CTA instead of a dead end.
    RETURN jsonb_build_object(
      'valid', false,
      'reason', 'accepted',
      'tenant_name', v_inv.tenant_name,
      'tenant_slug', v_inv.tenant_slug
    );
  END IF;

  IF v_inv.expires_at <= now() THEN
    RETURN jsonb_build_object(
      'valid', false,
      'reason', 'expired',
      'tenant_name', v_inv.tenant_name
    );
  END IF;

  -- Inviter's display name — graceful when the profile is missing
  -- (can happen if the inviter's profile row was deleted).
  SELECT display_name INTO v_inviter_name
  FROM public.profiles
  WHERE id = v_inv.invited_by;

  RETURN jsonb_build_object(
    'valid', true,
    'tenant_name', v_inv.tenant_name,
    'tenant_slug', v_inv.tenant_slug,
    'role', v_inv.role,
    'invited_email', v_inv.email,
    'invited_by_name', v_inviter_name,
    'expires_at', v_inv.expires_at
  );
END;
$function$;

GRANT ALL ON FUNCTION api.invitation_preview(uuid) TO anon;

CREATE FUNCTION api.invitation_resend (
  p_invitation_id uuid
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id uuid := (SELECT auth.uid());
  v_tenant_id uuid := public._auth_tenant_id();
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF v_tenant_id IS NULL THEN
    RAISE EXCEPTION 'No tenant selected';
  END IF;

  -- Primary permission gate (same permission that gates creating invitations).
  PERFORM public.auth_verify_access('invitation.create');

  -- Then confirm the invitation exists in the active tenant before delegating
  -- to the DEFINER helper (which re-checks role_permissions independently).
  IF NOT EXISTS (
    SELECT 1 FROM public.invitations
    WHERE id = p_invitation_id
      AND tenant_id = v_tenant_id
      AND accepted_at IS NULL
      AND expires_at > now()
  ) THEN
    RAISE EXCEPTION 'Invitation not found or not permitted';
  END IF;

  RETURN public._internal_admin_resend_invitation(v_user_id, p_invitation_id);
END;
$function$;

CREATE FUNCTION api.invitation_revoke (
  p_invitation_id uuid
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id uuid := (SELECT auth.uid());
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  -- Primary permission gate (403 if denied).
  PERFORM public.auth_verify_access('invitation.delete');

  -- Explicit tenant scope (the isolation RLS policy is the backstop).
  DELETE FROM public.invitations
  WHERE id = p_invitation_id
    AND tenant_id = (SELECT public._auth_tenant_id());

  IF NOT FOUND THEN
    -- Either the row doesn't exist or it's outside the active tenant.
    RAISE EXCEPTION 'Invitation not found or not permitted';
  END IF;

  RETURN jsonb_build_object('id', p_invitation_id);
END;
$function$;

CREATE FUNCTION api.membership_list()
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_tenant_id uuid := public._auth_tenant_id();
  v_result jsonb;
BEGIN
  IF v_tenant_id IS NULL THEN
    RAISE EXCEPTION 'No tenant selected';
  END IF;

  -- Primary permission gate: a caller without membership.read gets a clear
  -- 403 rather than a silent empty array. The WHERE below scopes to the
  -- active tenant; the memberships isolation RLS policy is the backstop.
  PERFORM public.auth_verify_access('membership.read');

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'id', m.id,
    'user_id', m.user_id,
    'role', m.role,
    'email', p.email,
    'display_name', p.display_name,
    'avatar_url', p.avatar_url,
    'created_at', m.created_at
  )), '[]'::jsonb)
  INTO v_result
  FROM public.memberships m
  LEFT JOIN public.profiles p ON p.id = m.user_id
  WHERE m.tenant_id = v_tenant_id;

  RETURN v_result;
END;
$function$;

CREATE FUNCTION api.membership_remove (
  p_membership_id uuid
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id uuid := (SELECT auth.uid());
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  -- Primary permission gate (403 if denied).
  PERFORM public.auth_verify_access('membership.delete');

  -- Explicit tenant scope + no self-removal (the memberships isolation RLS
  -- policy enforces both as the backstop).
  DELETE FROM public.memberships
  WHERE id = p_membership_id
    AND tenant_id = (SELECT public._auth_tenant_id())
    AND user_id != v_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Membership not found or not permitted';
  END IF;

  RETURN jsonb_build_object('id', p_membership_id);
END;
$function$;

CREATE FUNCTION api.membership_update_role (
  p_membership_id uuid,
  p_role          text
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id uuid := (SELECT auth.uid());
  v_role_invitable boolean;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  -- Primary permission gate (403 if denied).
  PERFORM public.auth_verify_access('membership.update');

  -- Owner is never assignable; matches the invitations CHECK constraint.
  IF p_role = 'owner' THEN
    RAISE EXCEPTION 'Role owner cannot be assigned';
  END IF;

  -- Validate the role exists and is invitable (mirrors invitation_create's check).
  SELECT invitable INTO v_role_invitable FROM public.roles WHERE name = p_role;
  IF v_role_invitable IS NULL THEN
    RAISE EXCEPTION 'Unknown role: %', p_role;
  ELSIF NOT v_role_invitable THEN
    RAISE EXCEPTION 'Role % cannot be assigned', p_role;
  END IF;

  -- Explicit tenant scope + no self-promotion (the memberships isolation RLS
  -- policy enforces both as the backstop).
  UPDATE public.memberships
  SET role = p_role
  WHERE id = p_membership_id
    AND tenant_id = (SELECT public._auth_tenant_id())
    AND user_id != v_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Membership not found or not permitted';
  END IF;

  RETURN jsonb_build_object('id', p_membership_id, 'role', p_role);
END;
$function$;

CREATE FUNCTION api.profile_get()
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_result JSONB;
BEGIN
  SELECT INTO v_result jsonb_build_object(
    'id', p.id,
    'email', p.email,
    'display_name', p.display_name,
    'avatar_url', p.avatar_url,
    'created_at', p.created_at
  )
  FROM public.profiles p
  WHERE p.id = (SELECT auth.uid());

  RETURN v_result;
END;
$function$;

CREATE FUNCTION api.profile_update (
  p_display_name text DEFAULT NULL::text,
  p_avatar_url   text DEFAULT NULL::text
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_result JSONB;
BEGIN
  UPDATE public.profiles SET
    display_name = COALESCE(p_display_name, display_name),
    avatar_url = COALESCE(p_avatar_url, avatar_url)
  WHERE id = (SELECT auth.uid());

  SELECT INTO v_result api.profile_get();
  RETURN v_result;
END;
$function$;

CREATE FUNCTION api.tenant_create (
  p_name text,
  p_slug text
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id   uuid := (SELECT auth.uid());
  v_tenant_id uuid;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  v_tenant_id := public._internal_admin_create_tenant(v_user_id, p_name, p_slug);

  -- Pin to this session so the next refresh starts in the new tenant. Skip
  -- when the caller has no session_id (rare — service-role calls or
  -- admin-API mints); the hook's "oldest membership" fallback resolves the
  -- tenant on next JWT mint anyway. The DEFINER helper reads session_id
  -- from auth.jwt() — never accepts it as a parameter — so this guard is
  -- only here to skip the call cleanly when there's no session at all.
  IF NULLIF(auth.jwt()->>'session_id', '') IS NOT NULL THEN
    PERFORM public._internal_admin_set_session_tenant(v_user_id, v_tenant_id, 'owner');
  END IF;

  RETURN jsonb_build_object(
    'id', v_tenant_id,
    'name', p_name,
    'slug', p_slug,
    'role', 'owner'
  );
END;
$function$;

CREATE FUNCTION api.tenant_list()
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_result jsonb;
BEGIN
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'id', t.id,
    'name', t.name,
    'slug', t.slug,
    'role', m.role
  )), '[]'::jsonb)
  INTO v_result
  FROM public.memberships m
  JOIN public.tenants t ON t.id = m.tenant_id
  WHERE m.user_id = (SELECT auth.uid());

  RETURN v_result;
END;
$function$;

CREATE FUNCTION api.tenant_select (
  p_tenant_id uuid
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id uuid := (SELECT auth.uid());
  v_role    text;
  v_tenant  record;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  -- Reads memberships for the calling user. Works under RLS thanks to the
  -- users_read_own_memberships policy added in multitenancy.sql.
  SELECT role INTO v_role
  FROM public.memberships
  WHERE tenant_id = p_tenant_id AND user_id = v_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Not a member of this tenant';
  END IF;

  -- Members can read their tenant via members_read_own_tenant policy.
  SELECT * INTO v_tenant
  FROM public.tenants
  WHERE id = p_tenant_id;

  -- The DEFINER helper reads session_id from auth.jwt() itself — never trusts
  -- a session_id passed by the caller.
  PERFORM public._internal_admin_set_session_tenant(v_user_id, p_tenant_id, v_role);

  RETURN jsonb_build_object(
    'id', v_tenant.id,
    'name', v_tenant.name,
    'slug', v_tenant.slug,
    'role', v_role
  );
END;
$function$;

CREATE FUNCTION public._auth_has_permission (
  p_permission text
)
  RETURNS boolean
  LANGUAGE sql
  STABLE
  SET search_path TO ''
  AS $function$
  SELECT COALESCE(
    (auth.jwt()->'app_metadata'->'permissions') ? p_permission,
    false
  );
$function$;

CREATE FUNCTION public._auth_has_role (
  p_minimum_role text
)
  RETURNS boolean
  LANGUAGE sql
  STABLE
  SET search_path TO ''
  AS $function$
  SELECT COALESCE(
    (SELECT rank FROM public.roles WHERE name = public._auth_tenant_role())
      >=
    (SELECT rank FROM public.roles WHERE name = p_minimum_role),
    false
  );
$function$;

CREATE FUNCTION public._auth_is_tenant_member (
  p_tenant_id uuid
)
  RETURNS boolean
  LANGUAGE sql
  STABLE
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.memberships
    WHERE tenant_id = p_tenant_id
      AND user_id = (SELECT auth.uid())
  );
$function$;

CREATE FUNCTION public._auth_tenant_id()
  RETURNS uuid
  LANGUAGE sql
  STABLE
  SET search_path TO ''
  AS $function$
  SELECT ((auth.jwt()->'app_metadata'->>'tenant_id')::uuid);
$function$;

CREATE FUNCTION public._auth_tenant_role()
  RETURNS text
  LANGUAGE sql
  STABLE
  SET search_path TO ''
  AS $function$
  SELECT (auth.jwt()->'app_metadata'->>'tenant_role');
$function$;

CREATE FUNCTION public._hook_before_user_created (
  event jsonb
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  allowed_domains text;
  user_email text;
  user_domain text;
  domain text;
  domains text[];
BEGIN
  allowed_domains := public._internal_admin_get_secret('ALLOWED_SIGNUP_DOMAINS');

  -- No restriction configured → allow all signups
  IF allowed_domains IS NULL OR trim(allowed_domains) = '' THEN
    RETURN event;
  END IF;

  user_email := event->'user'->>'email';
  IF user_email IS NULL OR user_email = '' THEN
    RETURN jsonb_build_object(
      'error', jsonb_build_object(
        'http_code', 400,
        'message', 'Email is required for signup.'
      )
    );
  END IF;

  user_domain := lower(split_part(user_email, '@', 2));
  domains := string_to_array(allowed_domains, ',');

  FOREACH domain IN ARRAY domains LOOP
    IF lower(trim(domain)) = user_domain THEN
      RETURN event;
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'error', jsonb_build_object(
      'http_code', 403,
      'message', 'Signups are restricted to authorized domains.'
    )
  );
END;
$function$;

REVOKE ALL ON FUNCTION public._hook_before_user_created(jsonb) FROM anon;

REVOKE ALL ON FUNCTION public._hook_before_user_created(jsonb) FROM authenticated;

GRANT ALL ON FUNCTION public._hook_before_user_created(jsonb) TO supabase_auth_admin;

CREATE FUNCTION public._hook_custom_access_token (
  event jsonb
)
  RETURNS jsonb
  LANGUAGE plpgsql
  STABLE
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  v_user_id          uuid;
  v_session_id       uuid;
  v_original_claims  jsonb := COALESCE(event->'claims', '{}'::jsonb);
  v_new_claims       jsonb := '{}'::jsonb;
  v_app_meta         jsonb := COALESCE(v_original_claims->'app_metadata', '{}'::jsonb);
  v_tenant_id        uuid;
  v_tenant_role      text;
  v_permissions      text[];
  v_claim            text;
BEGIN
  -- Safe parse: malformed/missing UUIDs collapse to NULL instead of erroring
  -- the whole function and dropping the JWT mint. event->>... returns NULL
  -- when the key is missing; ::uuid on a non-UUID text would raise — guard
  -- with a regex first. We could rely on Supabase always sending a valid
  -- UUID, but the cost of being defensive here is one regexp_match per mint.
  IF (event->>'user_id') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' THEN
    v_user_id := (event->>'user_id')::uuid;
  END IF;
  IF (v_original_claims->>'session_id') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' THEN
    v_session_id := (v_original_claims->>'session_id')::uuid;
  END IF;

  -- Build new_claims by copying ONLY the claims Supabase Auth's validator
  -- recognises. Matches the canonical "Custom Access Token Hook" example
  -- shape from the Supabase docs and is forward-compatible: anything else
  -- in the event we don't know about is silently dropped, which is the
  -- safe default (the validator rejects outputs containing claims it
  -- doesn't expect, which manifests as the JWT mint silently falling back
  -- to the original unmodified claims — a confusing failure mode).
  --   Required claims (validator errors if missing):
  --     iss, aud, exp, iat, sub, role, aal, session_id, email, phone, is_anonymous
  --   Optional claims worth preserving:
  --     user_metadata, amr, jti, nbf, client_id
  --   app_metadata is set explicitly below.
  FOREACH v_claim IN ARRAY ARRAY[
    'iss', 'aud', 'exp', 'iat', 'sub', 'role', 'aal',
    'session_id', 'email', 'phone', 'is_anonymous',
    'user_metadata', 'amr', 'jti', 'nbf', 'client_id'
  ] LOOP
    IF v_original_claims ? v_claim THEN
      v_new_claims := jsonb_set(v_new_claims, ARRAY[v_claim], v_original_claims->v_claim);
    END IF;
  END LOOP;

  -- Pass 1: per-session pin. user_id predicate is defense in depth — the
  -- only writer (api.tenant_select via _internal_admin_set_session_tenant)
  -- already enforces user_id = auth.uid(), but matching it here too means a
  -- session_tenants row with a wrong user_id (e.g. left over after sign-out
  -- + sign-in reuses a recycled session_id) won't inject the wrong tenant.
  IF v_session_id IS NOT NULL AND v_user_id IS NOT NULL THEN
    SELECT tenant_id, tenant_role
      INTO v_tenant_id, v_tenant_role
    FROM public.session_tenants
    WHERE session_id = v_session_id
      AND user_id    = v_user_id;
  END IF;

  -- Pass 2: fallback to oldest membership (single-tenant zero-touch).
  -- Hot path on every JWT mint when no pin is set — relies on the
  -- composite index idx_memberships_user_id_created_at to stop at row 1
  -- without a separate sort.
  IF v_tenant_id IS NULL AND v_user_id IS NOT NULL THEN
    SELECT tenant_id, role
      INTO v_tenant_id, v_tenant_role
    FROM public.memberships
    WHERE user_id = v_user_id
    ORDER BY created_at ASC
    LIMIT 1;
  END IF;

  -- Strip stale tenant claims that may have been in the original
  -- app_metadata, then add fresh ones if a tenant resolved. This matters
  -- because we preserve other app_metadata keys the application may have
  -- set (e.g. provider data) — we just want OUR three keys to be the
  -- authoritative source from the resolution above, not whatever was
  -- baked in previously.
  v_app_meta := v_app_meta - 'tenant_id' - 'tenant_role' - 'permissions';

  IF v_tenant_id IS NOT NULL THEN
    SELECT array_agg(permission_name)
      INTO v_permissions
    FROM public.role_permissions
    WHERE role_name = v_tenant_role;

    v_app_meta := v_app_meta || jsonb_build_object(
      'tenant_id',   v_tenant_id::text,
      'tenant_role', v_tenant_role,
      'permissions', COALESCE(to_jsonb(v_permissions), '[]'::jsonb)
    );
  END IF;

  v_new_claims := jsonb_set(v_new_claims, '{app_metadata}', v_app_meta);

  RETURN jsonb_build_object('claims', v_new_claims);
END;
$function$;

REVOKE ALL ON FUNCTION public._hook_custom_access_token(jsonb) FROM anon;

REVOKE ALL ON FUNCTION public._hook_custom_access_token(jsonb) FROM authenticated;

GRANT ALL ON FUNCTION public._hook_custom_access_token(jsonb) TO supabase_auth_admin;

