CREATE FUNCTION public._internal_admin_call_edge_function (
  function_name text,
  payload       jsonb DEFAULT '{}'::jsonb
)
  RETURNS bigint
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  supabase_url text;
  service_key text;
  request_id bigint;
  full_url text;
BEGIN
  supabase_url := public._internal_admin_get_secret('SUPABASE_URL');
  service_key := public._internal_admin_get_secret('SUPABASE_SECRET_KEY');

  IF supabase_url IS NULL THEN
    RAISE EXCEPTION 'SUPABASE_URL secret not found in Vault';
  END IF;

  IF service_key IS NULL THEN
    RAISE EXCEPTION 'SUPABASE_SECRET_KEY secret not found in Vault';
  END IF;

  full_url := supabase_url || '/functions/v1/' || function_name;

  SELECT net.http_post(
    url := full_url,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'apikey', service_key
    ),
    body := payload
  ) INTO request_id;

  RETURN request_id;
END;
$function$;

REVOKE ALL ON FUNCTION public._internal_admin_call_edge_function(text, jsonb) FROM anon;

REVOKE ALL ON FUNCTION public._internal_admin_call_edge_function(text, jsonb) FROM authenticated;

CREATE FUNCTION public._internal_admin_complete_invitation (
  p_user_id uuid,
  p_token   uuid
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  v_invitation record;
  v_tenant record;
  v_existing_role text;
BEGIN
  IF (SELECT auth.uid()) IS DISTINCT FROM p_user_id THEN
    RAISE EXCEPTION 'Cannot accept invitation on behalf of another user';
  END IF;

  SELECT * INTO v_invitation
  FROM public.invitations
  WHERE token = p_token
    AND accepted_at IS NULL
    AND expires_at > now();

  IF NOT FOUND THEN
    -- Idempotency: a user clicking the same invite link twice (slow first
    -- click, second tab, etc.) should land in the workspace, not see an error.
    -- If the token exists at all and the caller already has a membership in
    -- that tenant, treat as success. Otherwise the token is genuinely invalid.
    SELECT i.tenant_id, m.role
      INTO v_invitation.tenant_id, v_existing_role
    FROM public.invitations i
    LEFT JOIN public.memberships m
      ON m.tenant_id = i.tenant_id AND m.user_id = p_user_id
    WHERE i.token = p_token;

    IF v_existing_role IS NOT NULL THEN
      SELECT * INTO v_tenant FROM public.tenants WHERE id = v_invitation.tenant_id;
      RETURN jsonb_build_object(
        'id', v_tenant.id,
        'name', v_tenant.name,
        'slug', v_tenant.slug,
        'role', v_existing_role,
        'already_member', true
      );
    END IF;

    RAISE EXCEPTION 'Invalid or expired invitation';
  END IF;

  INSERT INTO public.memberships (tenant_id, user_id, role)
  VALUES (v_invitation.tenant_id, p_user_id, v_invitation.role)
  ON CONFLICT (tenant_id, user_id) DO NOTHING;

  UPDATE public.invitations
  SET accepted_at = now()
  WHERE id = v_invitation.id;

  SELECT * INTO v_tenant FROM public.tenants WHERE id = v_invitation.tenant_id;

  RETURN jsonb_build_object(
    'id', v_tenant.id,
    'name', v_tenant.name,
    'slug', v_tenant.slug,
    'role', v_invitation.role
  );
END;
$function$;

REVOKE ALL ON FUNCTION public._internal_admin_complete_invitation(uuid, uuid) FROM anon;

CREATE FUNCTION public._internal_admin_create_invitation (
  p_user_id   uuid,
  p_tenant_id uuid,
  p_email     text,
  p_role      text
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  v_invitation record;
  v_tenant_name text;
  v_caller_role text;
  v_role_invitable boolean;
BEGIN
  IF (SELECT auth.uid()) IS DISTINCT FROM p_user_id THEN
    RAISE EXCEPTION 'Cannot create invitation on behalf of another user';
  END IF;

  -- Caller must hold invitation.create in the target tenant. We resolve the role
  -- from the actual membership row (DEFINER bypasses RLS) rather than trusting
  -- JWT claims — guards against stale claims for users with multiple tenants —
  -- and check it against role_permissions.
  SELECT role INTO v_caller_role
  FROM public.memberships
  WHERE tenant_id = p_tenant_id AND user_id = p_user_id;

  IF v_caller_role IS NULL THEN
    RAISE EXCEPTION 'Not a member of this tenant';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.role_permissions
    WHERE role_name = v_caller_role
      AND permission_name = 'invitation.create'
  ) THEN
    RAISE EXCEPTION 'Your role does not permit creating invitations';
  END IF;

  -- The invited role must be marked invitable (default seed: 'owner' is not).
  SELECT invitable INTO v_role_invitable FROM public.roles WHERE name = p_role;
  IF v_role_invitable IS NULL THEN
    RAISE EXCEPTION 'Unknown role: %', p_role;
  ELSIF NOT v_role_invitable THEN
    RAISE EXCEPTION 'Role % cannot be assigned via invitation', p_role;
  END IF;

  INSERT INTO public.invitations (tenant_id, email, role, invited_by)
  VALUES (p_tenant_id, p_email, p_role, p_user_id)
  RETURNING * INTO v_invitation;

  SELECT name INTO v_tenant_name FROM public.tenants WHERE id = p_tenant_id;

  PERFORM api._admin_enqueue_task(
    'internal-invite-member',
    jsonb_build_object(
      'email', v_invitation.email,
      'token', v_invitation.token::text,
      'tenant_name', v_tenant_name
    )
  );

  RETURN jsonb_build_object(
    'id', v_invitation.id,
    'email', v_invitation.email,
    'role', v_invitation.role,
    'token', v_invitation.token,
    'expires_at', v_invitation.expires_at
  );
END;
$function$;

REVOKE ALL ON FUNCTION public._internal_admin_create_invitation(uuid, uuid, text, text) FROM anon;

CREATE FUNCTION public._internal_admin_create_tenant (
  p_user_id uuid,
  p_name    text,
  p_slug    text
)
  RETURNS uuid
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  v_tenant_id uuid;
BEGIN
  IF (SELECT auth.uid()) IS DISTINCT FROM p_user_id THEN
    RAISE EXCEPTION 'Cannot create tenant on behalf of another user';
  END IF;

  INSERT INTO public.tenants (name, slug)
  VALUES (p_name, p_slug)
  RETURNING id INTO v_tenant_id;

  INSERT INTO public.memberships (tenant_id, user_id, role)
  VALUES (v_tenant_id, p_user_id, 'owner');

  RETURN v_tenant_id;
END;
$function$;

REVOKE ALL ON FUNCTION public._internal_admin_create_tenant(uuid, text, text) FROM anon;

CREATE FUNCTION public._internal_admin_get_secret (
  secret_name text
)
  RETURNS text
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  secret_value text;
BEGIN
  SELECT decrypted_secret INTO secret_value
  FROM vault.decrypted_secrets
  WHERE name = secret_name
  LIMIT 1;

  RETURN secret_value;
END;
$function$;

REVOKE ALL ON FUNCTION public._internal_admin_get_secret(text) FROM anon;

REVOKE ALL ON FUNCTION public._internal_admin_get_secret(text) FROM authenticated;

CREATE FUNCTION public._internal_admin_handle_new_user()
  RETURNS trigger
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  v_display_name text;
  v_organization_name text;
  v_tenant_name text;
  v_tenant_id uuid;
  v_slug_base text;
  v_slug text;
  v_has_pending_invite boolean;
BEGIN
  v_display_name := COALESCE(
    NEW.raw_user_meta_data->>'display_name',
    NEW.raw_user_meta_data->>'full_name',
    NEW.raw_user_meta_data->>'name',
    split_part(NEW.email, '@', 1)
  );

  -- Org name from the signup form (NULL for OAuth, admin-created users, or
  -- forms that don't collect it — fall back to the auto-generated name).
  v_organization_name := NULLIF(trim(NEW.raw_user_meta_data->>'organization_name'), '');

  -- Create profile (always — every user needs one)
  INSERT INTO public.profiles (id, email, display_name, avatar_url)
  VALUES (
    NEW.id,
    NEW.email,
    v_display_name,
    COALESCE(
      NEW.raw_user_meta_data->>'avatar_url',
      NEW.raw_user_meta_data->>'picture'
    )
  );

  -- A pending invite means the user is intentionally being routed to an
  -- existing workspace; don't auto-create a parallel personal one.
  v_has_pending_invite := EXISTS (
    SELECT 1 FROM public.invitations
    WHERE lower(email) = lower(NEW.email)
      AND accepted_at IS NULL
      AND expires_at > now()
  );

  -- Skip personal tenant creation for two reasons:
  --   1. invited_at IS NOT NULL → user was admin-invited via generateLink
  --   2. A pending workspace invitation is waiting for this email
  IF NEW.invited_at IS NULL AND NOT v_has_pending_invite THEN
    v_tenant_name := COALESCE(v_organization_name, v_display_name || '''s Workspace');

    -- Slugify the tenant name; fall back to email local-part if slugification
    -- produces an empty string (e.g. all non-ASCII characters).
    v_slug_base := trim(both '-' from regexp_replace(lower(v_tenant_name), '[^a-z0-9]+', '-', 'g'));
    IF v_slug_base = '' THEN
      v_slug_base := regexp_replace(lower(split_part(NEW.email, '@', 1)), '[^a-z0-9]', '-', 'g');
    END IF;
    v_slug := v_slug_base || '-' || substr(replace(gen_random_uuid()::text, '-', ''), 1, 8);

    INSERT INTO public.tenants (name, slug)
    VALUES (v_tenant_name, v_slug)
    RETURNING id INTO v_tenant_id;

    INSERT INTO public.memberships (tenant_id, user_id, role)
    VALUES (v_tenant_id, NEW.id, 'owner');
  END IF;

  RETURN NEW;
END;
$function$;

CREATE FUNCTION public._internal_admin_resend_invitation (
  p_user_id       uuid,
  p_invitation_id uuid
)
  RETURNS jsonb
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  v_invitation record;
  v_tenant_name text;
  v_caller_role text;
BEGIN
  IF (SELECT auth.uid()) IS DISTINCT FROM p_user_id THEN
    RAISE EXCEPTION 'Cannot resend invitation on behalf of another user';
  END IF;

  SELECT * INTO v_invitation
  FROM public.invitations
  WHERE id = p_invitation_id
    AND accepted_at IS NULL
    AND expires_at > now();

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invitation not found or already accepted/expired';
  END IF;

  -- Permission gate: caller must be a tenant admin (invitation.create) of the
  -- invitation's tenant. Resolves from membership rows directly (bypassing RLS)
  -- to guard against stale JWT claims for users with multiple tenants.
  SELECT role INTO v_caller_role
  FROM public.memberships
  WHERE tenant_id = v_invitation.tenant_id AND user_id = p_user_id;

  IF v_caller_role IS NULL THEN
    RAISE EXCEPTION 'Not a member of this tenant';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.role_permissions
    WHERE role_name = v_caller_role
      AND permission_name = 'invitation.create'
  ) THEN
    RAISE EXCEPTION 'Your role does not permit resending invitations';
  END IF;

  SELECT name INTO v_tenant_name FROM public.tenants WHERE id = v_invitation.tenant_id;

  PERFORM api._admin_enqueue_task(
    'internal-invite-member',
    jsonb_build_object(
      'email', v_invitation.email,
      'token', v_invitation.token::text,
      'tenant_name', v_tenant_name
    )
  );

  RETURN jsonb_build_object(
    'id', v_invitation.id,
    'email', v_invitation.email,
    'expires_at', v_invitation.expires_at
  );
END;
$function$;

REVOKE ALL ON FUNCTION public._internal_admin_resend_invitation(uuid, uuid) FROM anon;

CREATE FUNCTION public._internal_admin_set_session_tenant (
  p_user_id   uuid,
  p_tenant_id uuid,
  p_role      text
)
  RETURNS void
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
DECLARE
  v_session_id uuid;
BEGIN
  IF (SELECT auth.uid()) IS DISTINCT FROM p_user_id THEN
    RAISE EXCEPTION 'Cannot set session tenant for another user';
  END IF;

  -- Read session_id from the caller's signed JWT — auth.jwt() works inside
  -- SECURITY DEFINER because the request-level GUC (request.jwt.claims) is
  -- session state, not role-bound. Whatever session_id we read here is by
  -- construction the calling user's real session.
  v_session_id := NULLIF((SELECT auth.jwt()->>'session_id'), '')::uuid;
  IF v_session_id IS NULL THEN
    RAISE EXCEPTION 'No session — JWT is missing session_id';
  END IF;

  INSERT INTO public.session_tenants (session_id, user_id, tenant_id, tenant_role, updated_at)
  VALUES (v_session_id, p_user_id, p_tenant_id, p_role, now())
  ON CONFLICT (session_id) DO UPDATE
    SET tenant_id   = EXCLUDED.tenant_id,
        tenant_role = EXCLUDED.tenant_role,
        user_id     = EXCLUDED.user_id,  -- safety: rewrite user_id to caller's
        updated_at  = now();
END;
$function$;

REVOKE ALL ON FUNCTION public._internal_admin_set_session_tenant(uuid, uuid, text) FROM anon;

CREATE FUNCTION public._internal_admin_sync_session_tenants_on_membership()
  RETURNS trigger
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO ''
  AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    DELETE FROM public.session_tenants
    WHERE user_id = OLD.user_id
      AND tenant_id = OLD.tenant_id;
    RETURN OLD;
  ELSIF TG_OP = 'UPDATE' AND OLD.role IS DISTINCT FROM NEW.role THEN
    UPDATE public.session_tenants
    SET tenant_role = NEW.role,
        updated_at  = now()
    WHERE user_id = NEW.user_id
      AND tenant_id = NEW.tenant_id;
  END IF;
  RETURN NEW;
END;
$function$;

CREATE FUNCTION public.auth_has_access (
  p_permission text
)
  RETURNS boolean
  LANGUAGE sql
  STABLE
  SET search_path TO ''
  AS $function$
  SELECT public._auth_has_permission(p_permission);
$function$;

CREATE FUNCTION public.auth_verify_access (
  p_permission text
)
  RETURNS void
  LANGUAGE plpgsql
  STABLE
  SET search_path TO ''
  AS $function$
BEGIN
  IF NOT public._auth_has_permission(p_permission) THEN
    RAISE EXCEPTION 'Permission denied: %', p_permission
      USING
        ERRCODE = '42501',  -- insufficient_privilege → PostgREST HTTP 403
        DETAIL  = 'The active workspace role does not grant this permission.',
        HINT    = 'Required permission: ' || p_permission;
  END IF;
END;
$function$;

CREATE FUNCTION public.set_updated_at()
  RETURNS trigger
  LANGUAGE plpgsql
  SET search_path TO ''
  AS $function$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$function$;

CREATE TABLE public.invitations (
  id          uuid                     DEFAULT gen_random_uuid() NOT NULL,
  tenant_id   uuid                     NOT NULL,
  email       text                     NOT NULL,
  role        text                     DEFAULT 'member'::text NOT NULL,
  invited_by  uuid                     NOT NULL,
  token       uuid                     DEFAULT gen_random_uuid() NOT NULL,
  expires_at  timestamp with time zone DEFAULT (now() + '7 days'::interval) NOT NULL,
  accepted_at timestamp with time zone,
  created_at  timestamp with time zone DEFAULT now() NOT NULL
);

ALTER TABLE public.invitations
  ENABLE ROW LEVEL SECURITY;

ALTER TABLE public.invitations
  ADD CONSTRAINT invitations_invited_by_fkey FOREIGN KEY (invited_by) REFERENCES auth.users(id);

ALTER TABLE public.invitations
  ADD CONSTRAINT invitations_pkey PRIMARY KEY (id);

ALTER TABLE public.invitations
  ADD CONSTRAINT invitations_role_check CHECK (role <> 'owner'::text);

ALTER TABLE public.invitations
  ADD CONSTRAINT invitations_token_key UNIQUE (token);

CREATE INDEX idx_invitations_token ON public.invitations (token)
  WHERE accepted_at IS NULL;

CREATE INDEX idx_invitations_tenant_id ON public.invitations (tenant_id);

CREATE POLICY authorized_delete_invitations ON public.invitations
  FOR DELETE
  TO authenticated
  USING ((tenant_id = ( SELECT public._auth_tenant_id() AS _auth_tenant_id)));

CREATE POLICY authorized_read_invitations ON public.invitations
  FOR SELECT
  TO authenticated
  USING ((tenant_id = ( SELECT public._auth_tenant_id() AS _auth_tenant_id)));

CREATE TABLE public.memberships (
  id         uuid                     DEFAULT gen_random_uuid() NOT NULL,
  tenant_id  uuid                     NOT NULL,
  user_id    uuid                     NOT NULL,
  role       text                     DEFAULT 'member'::text NOT NULL,
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

ALTER TABLE public.memberships
  ENABLE ROW LEVEL SECURITY;

ALTER TABLE public.memberships
  ADD CONSTRAINT memberships_pkey PRIMARY KEY (id);

ALTER TABLE public.memberships
  ADD CONSTRAINT memberships_tenant_id_user_id_key UNIQUE (tenant_id, user_id);

ALTER TABLE public.memberships
  ADD CONSTRAINT memberships_user_id_fkey FOREIGN KEY (user_id) REFERENCES auth.users(id)
    ON DELETE CASCADE;

CREATE INDEX idx_memberships_tenant_user ON public.memberships (tenant_id, user_id);

CREATE INDEX idx_memberships_user_id_created_at ON public.memberships (user_id, created_at);

CREATE TRIGGER trg_memberships_sync_session_tenants
  AFTER DELETE OR UPDATE ON public.memberships
  FOR EACH ROW
  EXECUTE FUNCTION public._internal_admin_sync_session_tenants_on_membership();

CREATE POLICY authorized_delete_memberships ON public.memberships
  FOR DELETE
  TO authenticated
  USING
    (((tenant_id = ( SELECT public._auth_tenant_id() AS _auth_tenant_id)) AND (user_id <> ( SELECT
    auth.uid() AS uid))));

CREATE POLICY authorized_insert_memberships ON public.memberships
  FOR INSERT
  TO authenticated
  WITH CHECK ((tenant_id = ( SELECT public._auth_tenant_id() AS _auth_tenant_id)));

CREATE POLICY authorized_update_memberships ON public.memberships
  FOR UPDATE
  TO authenticated
  USING
    (((tenant_id = ( SELECT public._auth_tenant_id() AS _auth_tenant_id)) AND (user_id <> ( SELECT
    auth.uid() AS uid))))
  WITH
    CHECK
    (((tenant_id = ( SELECT public._auth_tenant_id() AS _auth_tenant_id)) AND (user_id <> ( SELECT
    auth.uid() AS uid))));

CREATE POLICY members_read_memberships ON public.memberships
  FOR SELECT
  TO authenticated
  USING ((tenant_id = ( SELECT public._auth_tenant_id() AS _auth_tenant_id)));

CREATE POLICY users_read_own_memberships ON public.memberships
  FOR SELECT
  TO authenticated
  USING ((user_id = ( SELECT auth.uid() AS uid)));

