  TO authenticated
  USING (true);

CREATE TABLE public.session_tenants (
  session_id  uuid                     NOT NULL,
  user_id     uuid                     NOT NULL,
  tenant_id   uuid                     NOT NULL,
  tenant_role text                     NOT NULL,
  updated_at  timestamp with time zone DEFAULT now() NOT NULL
);

ALTER TABLE public.session_tenants
  ENABLE ROW LEVEL SECURITY;

ALTER TABLE public.session_tenants
  ADD CONSTRAINT session_tenants_pkey PRIMARY KEY (session_id);

ALTER TABLE public.session_tenants
  ADD CONSTRAINT session_tenants_session_id_fkey FOREIGN KEY (session_id)
    REFERENCES auth.sessions(id) ON DELETE CASCADE;

ALTER TABLE public.session_tenants
  ADD CONSTRAINT session_tenants_tenant_role_fkey FOREIGN KEY (tenant_role)
    REFERENCES public.roles(name) ON UPDATE CASCADE;

ALTER TABLE public.session_tenants
  ADD CONSTRAINT session_tenants_user_id_fkey FOREIGN KEY (user_id) REFERENCES auth.users(id)
    ON DELETE CASCADE;

REVOKE DELETE, INSERT, UPDATE ON public.session_tenants FROM anon;

REVOKE DELETE, INSERT, UPDATE ON public.session_tenants FROM authenticated;

GRANT SELECT ON public.session_tenants TO supabase_auth_admin;

CREATE INDEX idx_session_tenants_tenant_id ON public.session_tenants (tenant_id);

CREATE INDEX idx_session_tenants_user_tenant ON public.session_tenants (user_id, tenant_id);

CREATE POLICY users_read_own_session_tenants ON public.session_tenants
  FOR SELECT
  TO authenticated
  USING ((user_id = ( SELECT auth.uid() AS uid)));

CREATE TABLE public.tenants (
  id         uuid                     DEFAULT gen_random_uuid() NOT NULL,
  name       text                     NOT NULL,
  slug       text                     NOT NULL,
  created_at timestamp with time zone DEFAULT now() NOT NULL,
  updated_at timestamp with time zone DEFAULT now() NOT NULL
);

ALTER TABLE public.tenants
  ENABLE ROW LEVEL SECURITY;

ALTER TABLE public.tenants
  ADD CONSTRAINT tenants_pkey PRIMARY KEY (id);

ALTER TABLE public.invitations
  ADD CONSTRAINT invitations_tenant_id_fkey FOREIGN KEY (tenant_id) REFERENCES public.tenants(id)
    ON DELETE CASCADE;

ALTER TABLE public.memberships
  ADD CONSTRAINT memberships_tenant_id_fkey FOREIGN KEY (tenant_id) REFERENCES public.tenants(id)
    ON DELETE CASCADE;

ALTER TABLE public.session_tenants
  ADD CONSTRAINT session_tenants_tenant_id_fkey FOREIGN KEY (tenant_id)
    REFERENCES public.tenants(id) ON DELETE CASCADE;

ALTER TABLE public.tenants
  ADD CONSTRAINT tenants_slug_key UNIQUE (slug);

CREATE TRIGGER trg_tenants_updated_at
  BEFORE UPDATE ON public.tenants
  FOR EACH ROW
  EXECUTE FUNCTION public.set_updated_at();

CREATE POLICY authorized_delete_tenant ON public.tenants
  FOR DELETE
  TO authenticated
  USING (( SELECT public._auth_is_tenant_member(tenants.id) AS _auth_is_tenant_member));

CREATE POLICY authorized_update_tenant ON public.tenants
  FOR UPDATE
  TO authenticated
  USING (( SELECT public._auth_is_tenant_member(tenants.id) AS _auth_is_tenant_member));

CREATE POLICY members_read_own_tenant ON public.tenants
  FOR SELECT
  TO authenticated
  USING (( SELECT public._auth_is_tenant_member(tenants.id) AS _auth_is_tenant_member));

