-- ─────────────────────────────────────────────────────────────
-- Post-setup operations
-- pg-delta plan filters out auth/cron/pgmq schemas. The statements
-- below depend on those schemas — appended manually here.
-- ─────────────────────────────────────────────────────────────

-- Queue for async tasks (pgmq.create is a function call, not DDL).
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_tables WHERE schemaname = 'pgmq' AND tablename = 'q_agentlink_tasks'
  ) THEN
    PERFORM pgmq.create('agentlink_tasks');
  END IF;
END $$;

-- Cron job for the queue worker (fires every minute as the safety net
-- to the immediate-invocation path in _admin_enqueue_task).
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM cron.job WHERE jobname = 'process-stale-tasks') THEN
    PERFORM cron.schedule(
      'process-stale-tasks',
      '* * * * *',
      $cron$SELECT public._internal_admin_call_edge_function('internal-queue-worker')$cron$
    );
  END IF;
END $$;

-- Trigger on auth.users — runs after signup to create the profile row +
-- handle pending workspace invitations.
DROP TRIGGER IF EXISTS trg_auth_users_new_user ON auth.users;
CREATE TRIGGER trg_auth_users_new_user
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public._internal_admin_handle_new_user();

-- supabase_auth_admin (the GoTrue auth service role) needs USAGE on the
-- public schema to execute the _hook_* functions it calls during signup and
-- email flows. Supabase pre-grants public USAGE to postgres/anon/
-- authenticated/service_role but NOT to supabase_auth_admin, and this
-- script's platform-default strip (the broad "GRANT USAGE ON SCHEMA public"
-- rule in STRIP_PATTERNS) drops it from pg-delta's plan — so re-assert it
-- here. Without it a migration-built DB diverges from a db-apply-built one
-- (the drift guard flags exactly this). Idempotent.
GRANT USAGE ON SCHEMA public TO supabase_auth_admin;

-- Lock down the api._admin_* SECURITY DEFINER functions to service_role.
--
-- These bypass RLS and have no auth_verify_access guard — they're meant to
-- be called only by trusted server-side code (edge functions via the
-- service role). They live in the api schema, which IS exposed via
-- PostgREST, so a stray client grant is directly reachable.
--
-- WHY THIS IS HERE AND NOT IN THE pg-delta PLAN: Postgres grants EXECUTE to
-- PUBLIC by default on every new function. The declarative schemas
-- (_admin_queues.sql) revoke that with an explicit
-- "REVOKE ALL ... FROM PUBLIC, anon, authenticated", but pg-delta's plan
-- does NOT model the built-in PUBLIC default grant — it only emits
-- "REVOKE ... FROM authenticated" and leaves the implicit PUBLIC grant in
-- place. anon/authenticated are members of PUBLIC, so without this block a
-- migration-built DB (fresh prod via db push) would leave these privileged
-- functions anon-callable, diverging from a db-apply-built dev DB. Re-assert
-- the full revoke here so both paths converge. REVOKE is idempotent.
REVOKE ALL ON FUNCTION api._admin_enqueue_task(text, jsonb, integer) FROM PUBLIC, anon, authenticated;
REVOKE ALL ON FUNCTION api._admin_queue_read(integer, integer) FROM PUBLIC, anon, authenticated;
REVOKE ALL ON FUNCTION api._admin_queue_delete(bigint) FROM PUBLIC, anon, authenticated;
REVOKE ALL ON FUNCTION api._admin_queue_archive(bigint) FROM PUBLIC, anon, authenticated;

-- ── Table privileges on public.* (Supabase 2026 default change) ──────────────
--
-- Supabase no longer auto-grants SELECT/INSERT/UPDATE/DELETE to
-- anon/authenticated/service_role on new public tables. AgentLink's api.*
-- RPCs are SECURITY INVOKER, so they touch these tables AS the caller —
-- without these grants every RPC fails with "permission denied for table …".
-- RLS still gates rows, and public is not exposed via the Data API, so these
-- grants don't widen the REST surface. anon is omitted (anon-facing RPCs are
-- SECURITY DEFINER).
--
-- WHY THIS IS HERE AND NOT IN THE pg-delta PLAN (same reason as the REVOKEs
-- above): pg-delta's --integration supabase assumes the OLD default — that
-- anon/authenticated/service_role already hold full DML on public tables — so
-- it only emits DEVIATIONS (the rbac/session_tenants REVOKEs) and never the
-- base grants. Local Supabase images still apply the old default, so a
-- db-apply-built dev DB has these grants regardless; a migration-built DB on a
-- NEW-default cloud project would not. Re-assert the final desired state here
-- so both paths converge. GRANT is idempotent. Kept in sync with the GRANT
-- lines in supabase/schemas/public/{multitenancy,profiles,_rbac}.sql.
GRANT SELECT, INSERT, UPDATE, DELETE ON public.tenants       TO authenticated, service_role;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.memberships   TO authenticated, service_role;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.invitations   TO authenticated, service_role;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.profiles      TO authenticated, service_role;
-- Reference + session tables: service_role gets full DML (it seeds / writes via
-- DEFINER helpers); authenticated is read-only (matches the schema REVOKEs).
GRANT SELECT, INSERT, UPDATE, DELETE ON public.roles            TO service_role;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.permissions      TO service_role;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.role_permissions TO service_role;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.session_tenants  TO service_role;
GRANT SELECT ON public.roles, public.permissions, public.role_permissions, public.session_tenants TO authenticated;
